import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

type JsonValue = null | boolean | number | string | JsonValue[] | { [key: string]: JsonValue };
type JsonObject = { [key: string]: JsonValue };

const filename = fileURLToPath(import.meta.url);
const themeDirectory = path.dirname(filename);
const sourcePath = path.join(themeDirectory, 'tokens.json');
const generatedPath = path.join(themeDirectory, 'generated', 'tokens.ts');
const header =
  '// AUTO-GENERATED FROM src/theme/tokens.json.\n// DO NOT EDIT THIS FILE DIRECTLY.\n\n';

function isObject(value: JsonValue | undefined): value is JsonObject {
  return value !== null && typeof value === 'object' && !Array.isArray(value);
}

function readPath(root: JsonObject, tokenPath: string): JsonValue {
  let value: JsonValue = root;
  for (const segment of tokenPath.split('.')) {
    if (!isObject(value) || !(segment in value)) {
      throw new Error('Unknown token reference: {' + tokenPath + '}');
    }
    value = value[segment];
  }
  return value;
}

function resolveValue(value: JsonValue, root: JsonObject, stack: string[] = []): JsonValue {
  if (typeof value === 'string') {
    const reference = /^\{([^}]+)\}$/.exec(value);
    if (!reference) return value;
    const tokenPath = reference[1];
    if (stack.includes(tokenPath)) {
      throw new Error('Circular token reference: ' + [...stack, tokenPath].join(' -> '));
    }
    return resolveValue(readPath(root, tokenPath), root, [...stack, tokenPath]);
  }
  if (Array.isArray(value)) return value.map((entry) => resolveValue(entry, root, stack));
  if (!isObject(value)) return value;

  return Object.fromEntries(
    Object.keys(value)
      .filter((key) => !key.startsWith('_'))
      .sort()
      .map((key) => [key, resolveValue(value[key], root, stack)]),
  );
}

function stableStringify(value: JsonValue): string {
  const normalize = (entry: JsonValue): JsonValue => {
    if (Array.isArray(entry)) return entry.map(normalize);
    if (!isObject(entry)) return entry;
    return Object.fromEntries(
      Object.keys(entry)
        .sort()
        .map((key) => [key, normalize(entry[key])]),
    );
  };
  return JSON.stringify(normalize(value), null, 2);
}

function getObject(parent: JsonObject, key: string): JsonObject {
  const value = parent[key];
  if (!isObject(value)) throw new Error('Expected token object at ' + key);
  return value;
}

function getString(parent: JsonObject, key: string): string {
  const value = parent[key];
  if (typeof value !== 'string') throw new Error('Expected string token at ' + key);
  return value;
}

function relativeLuminance(hex: string): number {
  const match = /^#([0-9a-f]{6})$/i.exec(hex);
  if (!match) {
    throw new Error('Contrast validation requires a six-digit hex color, received ' + hex);
  }
  const channels = [0, 2, 4].map(
    (offset) => Number.parseInt(match[1].slice(offset, offset + 2), 16) / 255,
  );
  const [red, green, blue] = channels.map((channel) =>
    channel <= 0.04045 ? channel / 12.92 : ((channel + 0.055) / 1.055) ** 2.4,
  );
  return 0.2126 * red + 0.7152 * green + 0.0722 * blue;
}

function contrastRatio(foreground: string, background: string): number {
  const light = Math.max(relativeLuminance(foreground), relativeLuminance(background));
  const dark = Math.min(relativeLuminance(foreground), relativeLuminance(background));
  return (light + 0.05) / (dark + 0.05);
}

function validateTextContrast(colorSchemes: JsonObject): void {
  for (const schemeName of ['light', 'dark']) {
    const scheme = getObject(colorSchemes, schemeName);
    const text = getObject(scheme, 'text');
    const background = getObject(scheme, 'background');
    for (const textRole of ['primary', 'secondary']) {
      for (const surfaceRole of ['default', 'paper']) {
        const foreground = getString(text, textRole);
        const surface = getString(background, surfaceRole);
        const ratio = contrastRatio(foreground, surface);
        if (ratio < 4.5) {
          throw new Error(
            schemeName +
              '.' +
              textRole +
              ' on background.' +
              surfaceRole +
              ' has ' +
              ratio.toFixed(2) +
              ':1 contrast',
          );
        }
      }
    }
  }
}

function emitTokens(resolved: JsonObject): string {
  const tier1 = getObject(resolved, 'tier1');
  const tier2 = getObject(resolved, 'tier2');
  const tier3 = getObject(resolved, 'tier3');
  return (
    header +
    'export const brandPalette = ' +
    stableStringify(getObject(tier1, 'brandPalette')) +
    ' as const;\n\n' +
    'export const brandTypography = ' +
    stableStringify(getObject(tier1, 'brandTypography')) +
    ' as const;\n\n' +
    'export const layoutTokens = ' +
    stableStringify(getObject(tier1, 'layout')) +
    ' as const;\n\n' +
    'export const effectTokens = ' +
    stableStringify(getObject(tier1, 'effects')) +
    ' as const;\n\n' +
    'export const semanticColorSchemes = ' +
    stableStringify(getObject(tier2, 'colorSchemes')) +
    ' as const;\n\n' +
    'export const typography = ' +
    stableStringify(getObject(tier2, 'typography')) +
    ' as const;\n\n' +
    'export const shape = ' +
    stableStringify(getObject(tier2, 'shape')) +
    ' as const;\n\n' +
    'export const componentTokens = ' +
    stableStringify(tier3) +
    ' as const;\n\n' +
    'export const skeletonTokens = componentTokens.skeleton;\n'
  );
}

function main(): void {
  const raw = JSON.parse(fs.readFileSync(sourcePath, 'utf8')) as JsonValue;
  if (!isObject(raw)) throw new Error('tokens.json must contain a JSON object');
  const resolved = resolveValue(raw, raw);
  if (!isObject(resolved)) throw new Error('Resolved token source must be an object');
  validateTextContrast(getObject(getObject(resolved, 'tier2'), 'colorSchemes'));

  fs.mkdirSync(path.dirname(generatedPath), { recursive: true });
  fs.writeFileSync(generatedPath, emitTokens(resolved).replace(/\r\n/g, '\n'), 'utf8');
  console.log('Theme generated deterministically from tokens.json');
}

main();
